class QueryBuilder {
  constructor() {
    this.query = {};
    this.size = 10;
    this.from = 0;
    this.sort = [];
    this.aggregations = {};
    this.highlights = {};
    this.source = true;
  }

  setSize(size) {
    this.size = size;
    return this;
  }

  setFrom(from) {
    this.from = from;
    return this;
  }

  setBoolQuery(must = [], should = [], mustNot = [], filter = [], minimumShouldMatch = 0) {
    this.query = {
      bool: {
        ...(must.length > 0 && { must }),
        ...(should.length > 0 && { should }),
        ...(mustNot.length > 0 && { must_not: mustNot }),
        ...(filter.length > 0 && { filter }),
        ...(minimumShouldMatch > 0 && { minimum_should_match: minimumShouldMatch })
      }
    };
    return this;
  }

  setMatchQuery(field, query, operator = 'OR', fuzziness = 'AUTO') {
    this.query = {
      match: {
        [field]: {
          query,
          operator,
          fuzziness
        }
      }
    };
    return this;
  }

  setMultiMatchQuery(query, fields, type = 'best_fields', operator = 'OR') {
    this.query = {
      multi_match: {
        query,
        fields,
        type,
        operator
      }
    };
    return this;
  }

  setRangeQuery(field, gte, lte, gt, lt) {
    const rangeParams = {};
    if (gte !== undefined) rangeParams.gte = gte;
    if (lte !== undefined) rangeParams.lte = lte;
    if (gt !== undefined) rangeParams.gt = gt;
    if (lt !== undefined) rangeParams.lt = lt;

    this.query = {
      range: {
        [field]: rangeParams
      }
    };
    return this;
  }

  setFuzzyQuery(field, value, fuzziness = 'AUTO') {
    this.query = {
      fuzzy: {
        [field]: {
          value,
          fuzziness
        }
      }
    };
    return this;
  }

  setWildcardQuery(field, value) {
    this.query = {
      wildcard: {
        [field]: {
          value
        }
      }
    };
    return this;
  }

  setTermQuery(field, value) {
    this.query = {
      term: {
        [field]: {
          value
        }
      }
    };
    return this;
  }

  setTermsQuery(field, values) {
    this.query = {
      terms: {
        [field]: values
      }
    };
    return this;
  }

  setExistsQuery(field) {
    this.query = {
      exists: {
        field
      }
    };
    return this;
  }

  setPrefixQuery(field, value) {
    this.query = {
      prefix: {
        [field]: {
          value
        }
      }
    };
    return this;
  }

  setNestedQuery(path, query, scoreMode = 'avg') {
    this.query = {
      nested: {
        path,
        query,
        score_mode: scoreMode
      }
    };
    return this;
  }

  setFunctionScore(query, functions, scoreMode = 'multiply', boostMode = 'multiply', maxBoost) {
    this.query = {
      function_score: {
        query,
        functions,
        score_mode: scoreMode,
        boost_mode: boostMode,
        ...(maxBoost && { max_boost: maxBoost })
      }
    };
    return this;
  }

  setScriptScore(query, script, minScore) {
    this.query = {
      script_score: {
        query,
        script,
        ...(minScore && { min_score: minScore })
      }
    };
    return this;
  }

  addSort(field, order = 'asc', mode, missing) {
    const sortObj = {
      [field]: {
        order,
        ...(mode && { mode }),
        ...(missing && { missing })
      }
    };
    this.sort.push(sortObj);
    return this;
  }

  addAggregation(name, aggregation) {
    this.aggregations[name] = aggregation;
    return this;
  }

  setHighlight(fields, preTags = ['<em>'], postTags = ['</em>'], fragmentSize = 150) {
    this.highlights = {
      pre_tags: preTags,
      post_tags: postTags,
      fields: {}
    };
    
    fields.forEach(field => {
      this.highlights.fields[field] = { fragment_size: fragmentSize };
    });
    return this;
  }

  setSource(source) {
    this.source = source;
    return this;
  }

  build() {
    const body = {
      size: this.size,
      from: this.from,
      query: this.query
    };

    if (this.sort.length > 0) {
      body.sort = this.sort;
    }

    if (Object.keys(this.aggregations).length > 0) {
      body.aggs = this.aggregations;
    }

    if (Object.keys(this.highlights).length > 0) {
      body.highlight = this.highlights;
    }

    if (this.source !== true) {
      body._source = this.source;
    }

    return body;
  }
}

function sanitizeScript(script) {
  const dangerousPatterns = [
    /System\.exit/gi,
    /Runtime\.getRuntime/gi,
    /ProcessBuilder/gi,
    /\.exec\(/gi,
    /new\s+File/gi,
    /FileWriter/gi,
    /FileReader/gi,
    /__import__/gi,
    /eval\(/gi
  ];

  for (const pattern of dangerousPatterns) {
    if (pattern.test(script)) {
      throw new Error('Script contains potentially dangerous operations');
    }
  }

  return script;
}

function validateScriptParams(params) {
  if (!params || typeof params !== 'object') {
    return {};
  }

  const validated = {};
  for (const [key, value] of Object.entries(params)) {
    if (typeof value === 'string' || typeof value === 'number' || typeof value === 'boolean') {
      validated[key] = value;
    } else if (Array.isArray(value)) {
      validated[key] = value.filter(v => 
        typeof v === 'string' || typeof v === 'number' || typeof v === 'boolean'
      );
    }
  }

  return validated;
}

app.post('/api/search/basic', async (req, res) => {
  try {
    const {
      index,
      queryText,
      fields = ['*'],
      size = 10,
      from = 0,
      filters = [],
      sort = []
    } = req.body;

    if (!index) {
      return res.status(400).json({ error: 'Index name is required' });
    }

    const builder = new QueryBuilder();
    builder.setSize(size).setFrom(from);

    if (queryText) {
      if (fields.length === 1 && fields[0] !== '*') {
        builder.setMatchQuery(fields[0], queryText);
      } else {
        builder.setMultiMatchQuery(queryText, fields);
      }
    }

    if (filters.length > 0) {
      const must = queryText ? [builder.query] : [];
      builder.setBoolQuery(must, [], [], filters);
    }

    if (sort.length > 0) {
      sort.forEach(s => {
        builder.addSort(s.field, s.order || 'asc', s.mode, s.missing);
      });
    }

    const result = await esClient.search({
      index,
      body: builder.build()
    });

    res.json({
      total: result.hits.total,
      hits: result.hits.hits,
      took: result.took
    });
  } catch (error) {
    console.error('Search error:', error);
    res.status(500).json({ error: error.message });
  }
});

