app.post('/api/search/custom-dsl', async (req, res) => {
  try {
    const { index, body } = req.body;

    if (!index) {
      return res.status(400).json({ error: 'Index name is required' });
    }

    if (!body) {
      return res.status(400).json({ error: 'Query body is required' });
    }

    if (body.query && body.query.script_score && body.query.script_score.script) {
      const script = body.query.script_score.script;
      script.source = sanitizeScript(script.source);
      script.params = validateScriptParams(script.params || {});
    }

    if (body.query && body.query.function_score && body.query.function_score.functions) {
      body.query.function_score.functions = body.query.function_score.functions.map(func => {
        if (func.script_score) {
          const script = func.script_score.script;
          script.source = sanitizeScript(script.source);
          script.params = validateScriptParams(script.params || {});
        }
        return func;
      });
    }

    const result = await esClient.search({
      index,
      body
    });

    res.json({
      total: result.hits.total,
      hits: result.hits.hits,
      aggregations: result.aggregations,
      took: result.took
    });
  } catch (error) {
    console.error('Custom DSL search error:', error);
    res.status(500).json({ error: error.message });
  }
});

